define(['jquery', 'core/log'], function($, log) {
    "use strict";

    let isExamFinished = false;

    return {
        init: function() {
            log.debug("🚀 SUT Exam Protector: Clean UI Edition");

            this.injectStrictStyles();
            this.setupInteractionsSecurity(); 
            this.setupKeyboardSecurity();    
            this.setupStartButton();

            document.addEventListener("fullscreenchange", () => {
                if (!document.fullscreenElement && !isExamFinished) {
                    this.handleViolation("คุณออกจากโหมดเต็มจอ", "กรุณากลับเข้าสู่หน้าจอสอบเพื่อทำข้อสอบต่อ");
                }
            });

            window.addEventListener('blur', () => {
                if (!isExamFinished) {
                    this.handleViolation("ตรวจพบการสลับหน้าต่าง", "กรุณาโฟกัสที่หน้าจอสอบเท่านั้นเพื่อป้องกันการทุจริต");
                }
            });

            this.preventBackNavigation();

            window.onbeforeunload = (e) => {
                if (!isExamFinished) {
                    e.preventDefault();
                    e.returnValue = "คำเตือน! การสอบยังไม่สิ้นสุด";
                    return e.returnValue;
                }
            };

            this.observeSubmitButton();
        },

        setupInteractionsSecurity: function() {
            const silentBlock = (e) => {
                e.preventDefault();
                e.stopImmediatePropagation();
                return false;
            };
            document.addEventListener('contextmenu', silentBlock, true);
            document.addEventListener('selectstart', silentBlock, true);
            ['copy', 'cut', 'paste', 'dragstart', 'drop'].forEach(event => {
                document.addEventListener(event, silentBlock, true);
            });
        },

        setupKeyboardSecurity: function() {
            document.addEventListener('keydown', (e) => {
                const key = e.key.toLowerCase();
                const isCtrlOrMeta = e.ctrlKey || e.metaKey;
                const forbiddenKeys = ['s', 'c', 'v', 'a', 'p', 'u' , 'f4', 'tab', 'escape', 'w', 'q', 'e', 'r', 't', 'y', 'z', 'x' ,'f', 'g', 'h', 'j', 'k', 'l', 'm', 'n' ,'shift' ];

                if ((isCtrlOrMeta && forbiddenKeys.includes(key)) || e.key === 'F12' || e.keyCode === 123 || e.altKey) {
                    e.preventDefault();
                    e.stopImmediatePropagation();
                    return false;
                }
            }, true);
        },

        injectStrictStyles: function() {
            const style = document.createElement('style');
            style.innerHTML = `
                @import url('https://fonts.googleapis.com/css2?family=Kanit:wght@300;400;600&display=swap');
                * { -webkit-user-select: none !important; user-select: none !important; font-family: 'Kanit', sans-serif; }
                input, textarea { -webkit-user-select: text !important; user-select: text !important; }
                ::-webkit-scrollbar { display: none; }
                html, body { overflow: hidden !important; height: 100vh !important; width: 100vw !important; margin: 0 !important; background: #f8f9fa; }
                
                /* คลีนดีไซน์สำหรับ Overlay */
                .sut-overlay { 
                    position: fixed; top: 0; left: 0; width: 100vw; height: 100vh; 
                    background: rgba(15, 23, 42, 0.9); backdrop-filter: blur(8px); 
                    z-index: 10000000; display: flex; justify-content: center; align-items: center; 
                    transition: all 0.3s ease;
                }
                .sut-modal { 
                    background: white; padding: 40px; border-radius: 24px; text-align: center; 
                    box-shadow: 0 20px 25px -5px rgba(0, 0, 0, 0.1), 0 10px 10px -5px rgba(0, 0, 0, 0.04); 
                    max-width: 400px; width: 90%; border: none;
                }
                .sut-btn { 
                    margin-top: 24px; padding: 12px 32px; font-size: 16px; 
                    background: #2563eb; color: white; border: none; border-radius: 12px; 
                    cursor: pointer; font-weight: 600; width: 100%; transition: background 0.2s;
                }
                .sut-btn:hover { background: #1d4ed8; }
                .sut-title { color: #1e293b; font-size: 22px; font-weight: 600; margin-bottom: 8px; }
                .sut-desc { color: #64748b; font-size: 15px; line-height: 1.5; }
            `;
            document.head.appendChild(style);
        },

        handleViolation: function(title, desc) {
            if (document.getElementById("custom-alert-overlay")) return;
            let warningDiv = document.createElement("div");
            warningDiv.id = "custom-alert-overlay";
            warningDiv.className = "sut-overlay";
            warningDiv.innerHTML = `
                <div class="sut-modal">
                    <div style="font-size: 48px; margin-bottom: 16px;">🔐</div>
                    <div class="sut-title">${title}</div>
                    <div class="sut-desc">${desc}</div>
                    <button id="confirm-re-fs" class="sut-btn">กลับเข้าสู่การสอบ</button>
                </div>
            `;
            document.body.appendChild(warningDiv);
            document.getElementById("confirm-re-fs").onclick = () => {
                warningDiv.remove();
                this.forceFullscreen();
            };
        },

        forceFullscreen: function() {
            let elem = document.documentElement;
            if (elem.requestFullscreen) { elem.requestFullscreen().catch(() => {}); }
            else if (elem.webkitRequestFullscreen) { elem.webkitRequestFullscreen().catch(() => {}); }
        },

        setupStartButton: function() {
            let overlay = document.createElement("div");
            overlay.className = "sut-overlay";
            overlay.innerHTML = `
                <div class="sut-modal" style="max-width: 450px;">
                    <div style="font-size: 56px; margin-bottom: 20px;">🚀</div>
                    <div class="sut-title">SUT Exam Protector</div>
                    <div class="sut-desc">เพื่อความโปร่งใสในการสอบ ระบบจะทำงานในโหมดเต็มจอและจำกัดการเข้าถึงหน้าต่างอื่น</div>
                    <button id="enter-btn" class="sut-btn">เริ่มทำข้อสอบ</button>
                </div>`;
            document.body.appendChild(overlay);
            document.getElementById("enter-btn").onclick = () => { 
                this.forceFullscreen(); 
                overlay.remove(); 
            };
        },

        preventBackNavigation: function() {
            history.pushState(null, null, location.href);
            window.onpopstate = () => {
                if (!isExamFinished) {
                    if (document.fullscreenElement || document.webkitFullscreenElement) {
                        document.exitFullscreen().catch(() => {});
                    }
                    this.handleViolation("ตรวจพบการกดย้อนกลับ", "ระบบหยุดเวลาไว้ชั่วคราวเพื่อความปลอดภัย กรุณากดปุ่มด้านล่างเพื่อเข้าสู่หน้าจอสอบอีกครั้ง");
                    history.pushState(null, null, location.href);
                }
            };
        },

        observeSubmitButton: function() {
            $(document).on('click', 'button, input[type="submit"]', (e) => {
                let text = ($(e.currentTarget).text() || $(e.currentTarget).val() || "").toLowerCase();
                if (["finish", "submit", "ส่ง", "เสร็จ"].some(kw => text.includes(kw))) {
                    isExamFinished = true;
                    window.onbeforeunload = null;
                }
            });
        }
    };
});